@dataclass
class Vector3:
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0

    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )

    def to_dict(self) -> dict:
        return {"x": self.x, "y": self.y, "z": self.z}

    @staticmethod
    def from_dict(data: dict) -> 'Vector3':
        return Vector3(x=data.get("x", 0), y=data.get("y", 0), z=data.get("z", 0))


@dataclass
class Obstacle:
    position: Vector3
    width: float
    height: float
    depth: float
    obstacle_id: str = ""

    def to_dict(self) -> dict:
        return {
            "obstacle_id": self.obstacle_id,
            "position": self.position.to_dict(),
            "width": self.width,
            "height": self.height,
            "depth": self.depth,
        }

    def get_bounds(self) -> Tuple[float, float, float, float]:
        half_w = self.width / 2
        half_d = self.depth / 2
        return (
            self.position.x - half_w,
            self.position.z - half_d,
            self.position.x + half_w,
            self.position.z + half_d,
        )


