@dataclass
class Player:
    player_id: str
    username: str
    position: Vector3 = field(default_factory=Vector3)
    velocity: Vector3 = field(default_factory=lambda: Vector3(0, 0, 0))
    rotation: float = 0.0  # yaw in degrees
    pitch: float = 0.0
    health: float = 100.0
    armor: float = 0.0
    state: PlayerState = PlayerState.ALIVE
    kills: int = 0
    damage_dealt: float = 0.0
    team_id: Optional[str] = None
    weapons: List[Weapon] = field(default_factory=list)
    active_weapon_index: int = 0
    inventory: Dict[str, int] = field(default_factory=dict)
    last_shot_time: float = 0.0
    last_hit_time: float = 0.0
    last_update_time: float = 0.0
    is_reloading: bool = False
    reload_start_time: float = 0.0
    is_crouching: bool = False
    is_sprinting: bool = False
    connected: bool = True
    websocket: Optional[object] = None

    def to_dict(self, include_private: bool = False) -> dict:
        data = {
            "player_id": self.player_id,
            "username": self.username,
            "position": self.position.to_dict(),
            "velocity": self.velocity.to_dict(),
            "rotation": self.rotation,
            "pitch": self.pitch,
            "health": self.health,
            "armor": self.armor,
            "state": self.state.value,
            "kills": self.kills,
            "team_id": self.team_id,
            "active_weapon_index": self.active_weapon_index,
            "weapons": [w.to_dict() for w in self.weapons],
            "is_crouching": self.is_crouching,
            "is_sprinting": self.is_sprinting,
            "is_reloading": self.is_reloading,
        }
        if include_private:
            data["inventory"] = self.inventory
            data["damage_dealt"] = self.damage_dealt
        return data

    def get_active_weapon(self) -> Optional[Weapon]:
        if 0 <= self.active_weapon_index < len(self.weapons):
            return self.weapons[self.active_weapon_index]
        return None


