class GameMap:
    def __init__(self, width: float = 2000, depth: float = 2000):
        self.width = width
        self.depth = depth
        self.obstacles: List[Obstacle] = []
        self.loot_items: Dict[str, LootItem] = {}
        self._generate_map()
        self._spawn_loot()

    def _generate_map(self):
        random.seed(42)
        num_buildings = 80
        for i in range(num_buildings):
            w = random.uniform(10, 40)
            h = random.uniform(5, 25)
            d = random.uniform(10, 40)
            x = random.uniform(-self.width / 2 + w, self.width / 2 - w)
            z = random.uniform(-self.depth / 2 + d, self.depth / 2 - d)
            obs = Obstacle(
                position=Vector3(x, h / 2, z),
                width=w, height=h, depth=d,
                obstacle_id=f"obs_{i}"
            )
            self.obstacles.append(obs)

        num_walls = 120
        for i in range(num_walls):
            is_horizontal = random.random() > 0.5
            if is_horizontal:
                w = random.uniform(15, 50)
                d = random.uniform(0.5, 2)
            else:
                w = random.uniform(0.5, 2)
                d = random.uniform(15, 50)
            h = random.uniform(3, 8)
            x = random.uniform(-self.width / 2 + 50, self.width / 2 - 50)
            z = random.uniform(-self.depth / 2 + 50, self.depth / 2 - 50)
            obs = Obstacle(
                position=Vector3(x, h / 2, z),
                width=w, height=h, depth=d,
                obstacle_id=f"wall_{i}"
            )
            self.obstacles.append(obs)

    def _spawn_loot(self):
        num_loot = 500
        for i in range(num_loot):
            total_weight = sum(w for _, _, w in LOOT_TABLE)
            roll = random.uniform(0, total_weight)
            cumulative = 0
            chosen_type = "weapon"
            chosen_name = "pistol"
            for item_type, item_name, weight in LOOT_TABLE:
                cumulative += weight
                if roll <= cumulative:
                    chosen_type = item_type
                    chosen_name = item_name
                    break

            x = random.uniform(-self.width / 2 + 10, self.width / 2 - 10)
            z = random.uniform(-self.depth / 2 + 10, self.depth / 2 - 10)
            item_id = f"loot_{i}"
            quantity = 1
            if chosen_type == "ammo":
                quantity = random.randint(20, 60)
            item = LootItem(
                item_id=item_id,
                position=Vector3(x, 0, z),
                item_type=chosen_type,
                item_name=chosen_name,
                quantity=quantity,
            )
            self.loot_items[item_id] = item

    def line_intersects_obstacle(self, start: Vector3, end: Vector3, obstacle: Obstacle) -> bool:
        min_x, min_z, max_x, max_z = obstacle.get_bounds()
        min_y = 0
        max_y = obstacle.height

        dx = end.x - start.x
        dy = end.y - start.y
        dz = end.z - start.z

        t_min = 0.0
        t_max = 1.0

        for axis_min, axis_max, origin, direction in [
            (min_x, max_x, start.x, dx),
            (min_y, max_y, start.y, dy),
            (min_z, max_z, start.z, dz),
        ]:
            if abs(direction) < 1e-9:
                if origin < axis_min or origin > axis_max:
                    return False
            else:
                t1 = (axis_min - origin) / direction
                t2 = (axis_max - origin) / direction
                if t1 > t2:
                    t1, t2 = t2, t1
                t_min = max(t_min, t1)
                t_max = min(t_max, t2)
                if t_min > t_max:
                    return False

        return True

    def has_line_of_sight(self, start: Vector3, end: Vector3) -> bool:
        for obstacle in self.obstacles:
            dist = start.distance_to(obstacle.position)
            if dist > 300:
                continue
            if self.line_intersects_obstacle(start, end, obstacle):
                return False
        return True

    def get_obstacles_data(self) -> List[dict]:
        return [obs.to_dict() for obs in self.obstacles]

    def get_available_loot(self) -> List[dict]:
        return [
            item.to_dict()
            for item in self.loot_items.values()
            if not item.picked_up
        ]


class BattleRoyaleServer:
    def __init__(
        self,
        host: str = "0.0.0.0",
        port: int = 8765,
        tick_rate: int = 20,
        max_players: int = 100,
        min_players_to_start: int = 2,
    ):
        self.host = host
        self.port = port
        self.tick_rate = tick_rate
        self.tick_interval = 1.0 / tick_rate
        self.max_players = max_players
        self.min_players_to_start = min_players_to_start

        self.players: Dict[str, Player] = {}
        self.projectiles: Dict[str, Projectile] = {}
        self.game_map = GameMap()
        self.game_phase = GamePhase.WAITING
        self.game_start_time: float = 0
        self.server_tick: int = 0

        self.zone = Zone(
            center=Vector3(0, 0, 0),
            current_radius=1000,
            target_radius=1000,
            shrink_rate=0,
            damage_per_second=1,
            phase=0,
            next_shrink_time=0,
        )

        self.zone_phases = [
            {"delay": 120, "target_radius": 700, "shrink_rate": 5, "damage": 1},
            {"delay": 90, "target_radius": 450, "shrink_rate": 6, "damage": 2},
            {"delay": 75, "target_radius": 250, "shrink_rate": 7, "damage": 5},
            {"delay": 60, "target_radius": 120, "shrink_rate": 8, "damage": 8},
            {"delay": 45, "target_radius": 50, "shrink_rate": 10, "damage": 12},
            {"delay": 30, "target_radius": 10, "shrink_rate": 12, "damage": 20},
            {"delay": 15, "target_radius": 0, "shrink_rate": 15, "damage": 50},
        ]

        self.kill_feed: List[dict] = []
        self.event_queue: List[dict] = []
        self.connected_websockets: Dict[str, websockets.WebSocketServerProtocol] = {}

        self.move_speed = 8.0
        self.sprint_multiplier = 1.6
        self.crouch_multiplier = 0.5

    async def start(self):
        logger.info(f"Starting Battle Royale Server on {self.host}:{self.port}")
        logger.info(f"Tick rate: {self.tick_rate} Hz, Max players: {self.max_players}")

        server = await websockets.serve(
            self.handle_connection,
            self.host,
            self.port,
            ping_interval=20,
            ping_timeout=60,
            max_size=2**20,
        )

        game_loop_task = asyncio.create_task(self.game_loop())

        logger.info("Server is running!")
        await asyncio.gather(server.wait_closed(), game_loop_task)

    async def handle_connection(self, websocket, path=None):
        player_id = str(uuid.uuid4())[:8]
        logger.info(f"New connection from {websocket.remote_address}, assigned ID: {player_id}")

        try:
            async for message in websocket:
                try:
                    data = json.loads(message)
                    msg_type = data.get("type")

                    if msg_type == "join":
                        await self.handle_join(player_id, data, websocket)
                    elif msg_type == "move":
                        await self.handle_move(player_id, data)
                    elif msg_type == "shoot":
                        await self.handle_shoot(player_id, data)
                    elif msg_type == "reload":
                        await self.handle_reload(player_id)
                    elif msg_type == "switch_weapon":
                        await self.handle_switch_weapon(player_id, data)
                    elif msg_type == "pickup":
                        await self.handle_pickup(player_id, data)
                    elif msg_type == "drop":
                        await self.handle_drop(player_id, data)
                    elif msg_type == "use_item":
                        await self.handle_use_item(player_id, data)
                    elif msg_type == "ping":
                        await self.send_to_player(player_id, {
                            "type": "pong",
                            "server_time": time.time(),
                            "client_time": data.get("client_time", 0),
                        })
                except json.JSONDecodeError:
                    logger.warning(f"Invalid JSON from player {player_id}")
                except Exception as e:
                    logger.error(f"Error handling message from {player_id}: {e}")

        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Player {player_id} disconnected")
        finally:
            await self.handle_disconnect(player_id)

    async def handle_join(self, player_id: str, data: dict, websocket):
        if len(self.players) >= self.max_players:
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Server is full"
            }))
            return

        if self.game_phase not in (GamePhase.WAITING, GamePhase.DROPPING):
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Game already in progress"
            }))
            return

        username = data.get("username", f"Player_{player_id}")
        team_id = data.get("team_id")

        spawn_x = random.uniform(-800, 800)
        spawn_z = random.uniform(-800, 800)

        player = Player(
            player_id=player_id,
            username=username,
            position=Vector3(spawn_x, 100, spawn_z),
            team_id=team_id,
            websocket=websocket,
            last_update_time=time.time(),
        )

        default_weapon = Weapon(**{
            "name": WEAPON_TEMPLATES["pistol"].name,
            "damage": WEAPON_TEMPLATES["pistol"].damage,
            "fire_rate": WEAPON_TEMPLATES["pistol"].fire_rate,
            "magazine_size": WEAPON_TEMPLATES["pistol"].magazine_size,
            "current_ammo": WEAPON_TEMPLATES["pistol"].magazine_size,
            "reload_time": WEAPON_TEMPLATES["pistol"].reload_time,
            "projectile_speed": WEAPON_TEMPLATES["pistol"].projectile_speed,
            "weapon_range": WEAPON_TEMPLATES["pistol"].weapon_range,
        })
        player.weapons.append(default_weapon)
        player.inventory = {"light_ammo": 36, "bandage": 3}

        self.players[player_id] = player
        self.connected_websockets[player_id] = websocket

        await self.send_to_player(player_id, {
            "type": "join_ack",
            "player_id": player_id,
            "player_data": player.to_dict(include_private=True),
            "map_data": {
                "width": self.game_map.width,
                "depth": self.game_map.depth,
                "obstacles": self.game_map.get_obstacles_data(),
            },
            "zone": self.zone.to_dict(),
            "game_phase": self.game_phase.value,
            "server_tick_rate": self.tick_rate,
            "server_time": time.time(),
        })

        self.event_queue.append({
            "type": "player_joined",
            "player_id": player_id,
            "username": username,
            "player_count": len([p for p in self.players.values() if p.connected]),
        })

        logger.info(f"Player {username} ({player_id}) joined. "
                     f"Total players: {len(self.players)}")

    async def handle_move(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        now = time.time()
        dt = now - player.last_update_time
        dt = min(dt, 0.1)

        input_x = max(-1.0, min(1.0, data.get("input_x", 0)))
        input_z = max(-1.0, min(1.0, data.get("input_z", 0)))
        rotation = data.get("rotation", player.rotation)
        pitch = data.get("pitch", player.pitch)
        is_crouching = data.get("is_crouching", False)
        is_sprinting = data.get("is_sprinting", False)

        speed = self.move_speed
        if is_sprinting and not is_crouching:
            speed *= self.sprint_multiplier
        elif is_crouching:
            speed *= self.crouch_multiplier

        rad = math.radians(rotation)
        forward_x = math.sin(rad)
        forward_z = math.cos(rad)
        right_x = math.cos(rad)
        right_z = -math.sin(rad)

        move_x = (forward_x * input_z + right_x * input_x) * speed
        move_z = (forward_z * input_z + right_z * input_x) * speed

        new_x = player.position.x + move_x * dt
        new_z = player.position.z + move_z * dt

        half_w = self.game_map.width / 2
        half_d = self.game_map.depth / 2
        new_x = max(-half_w, min(half_w, new_x))
        new_z = max(-half_d, min(half_d, new_z))

        collision = False
        player_radius = 0.5
        for obs in self.game_map.obstacles:
            min_x, min_z, max_x, max_z = obs.get_bounds()
            closest_x = max(min_x, min(new_x, max_x))
            closest_z = max(min_z, min(new_z, max_z))
            dist_x = new_x - closest_x
            dist_z = new_z - closest_z
            if dist_x * dist_x + dist_z * dist_z < player_radius * player_radius:
                collision = True
                break

        if not collision:
            player.position.x = new_x
            player.position.z = new_z

        player.position.y = 0 if not is_crouching else -0.5
        player.velocity = Vector3(move_x, 0, move_z)
        player.rotation = rotation
        player.pitch = max(-89, min(89, pitch))
        player.is_crouching = is_crouching
        player.is_sprinting = is_sprinting
        player.last_update_time = now

    async def handle_shoot(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        weapon = player.get_active_weapon()
        if not weapon:
            return

        now = time.time()
        min_interval = 1.0 / weapon.fire_rate
        if now - player.last_shot_time < min_interval:
            return

        if player.is_reloading:
            return

        if weapon.current_ammo <= 0:
            await self.send_to_player(player_id, {"type": "empty_magazine"})
            return

        weapon.current_ammo -= 1
        player.last_shot_time = now

        aim_x = data.get("aim_x", 0)
        aim_y = data.get("aim_y", 0)
        aim_z = data.get("aim_z", 1)
        magnitude = math.sqrt(aim_x ** 2 + aim_y ** 2 + aim_z ** 2)
        if magnitude > 0:
            aim_x /= magnitude
            aim_y /= magnitude
            aim_z /= magnitude

        spread = 0.02
        if player.is_crouching:
            spread *= 0.6
        if player.is_sprinting:
            spread *= 2.0

        aim_x += random.uniform(-spread, spread)
        aim_y += random.uniform(-spread, spread)
        aim_z += random.uniform(-spread, spread)

        eye_height = 1.6 if not player.is_crouching else 1.0
        start_pos = Vector3(
            player.position.x,
            player.position.y + eye_height,
            player.position.z,
        )

        hit_result = self._raycast(
            start_pos, Vector3(aim_x, aim_y, aim_z),
            weapon.weapon_range, player_id
        )

        projectile_id = str(uuid.uuid4())[:8]

        if hit_result:
            hit_type, hit_target, hit_pos, hit_dist = hit_result
            if hit_type == "player":
                target = self.players.get(hit_target)
                if target and target.state == PlayerState.ALIVE:
                    damage = weapon.damage
                    headshot = abs(hit_pos.y - (target.position.y + 1.7)) < 0.3
                    if headshot:
                        damage *= 2.0

                    actual_damage = self._apply_damage(target, damage)
                    player.damage_dealt += actual_damage

                    self.event_queue.append({
                        "type": "hit_marker",
                        "shooter_id": player_id,
                        "target_id": hit_target,
                        "damage": actual_damage,
                        "headshot": headshot,
                        "position": hit_pos.to_dict(),
                    })

                    if target.health <= 0:
                        target.state = PlayerState.DEAD
                        player.kills += 1
                        kill_event = {
                            "type": "kill",
                            "killer_id": player_id,
                            "killer_name": player.username,
                            "victim_id": hit_target,
                            "victim_name": target.username,
                            "weapon": weapon.name,
                            "headshot": headshot,
                            "timestamp": now,
                        }
                        self.kill_feed.append(kill_event)
                        self.event_queue.append(kill_event)

        self.event_queue.append({
            "type": "shot_fired",
            "player_id": player_id,
            "position": start_pos.to_dict(),
            "direction": {"x": aim_x, "y": aim_y, "z": aim_z},
            "weapon": weapon.name,
            "hit": hit_result[0] if hit_result else None,
            "hit_position": hit_result[2].to_dict() if hit_result else None,
        })

    def _raycast(
        self,
        origin: Vector3,
        direction: Vector3,
        max_dist: float,
        ignore_player: str,
    ) -> Optional[Tuple[str, str, Vector3, float]]:
        closest_hit = None
        closest_dist = max_dist

        for pid, player in self.players.items():
            if pid == ignore_player or player.state != PlayerState.ALIVE:
                continue

            player_center = Vector3(
                player.position.x,
                player.position.y + 0.9,
                player.position.z,
            )
            player_radius = 0.4
            player_height = 1.8 if not player.is_crouching else 1.2

            oc = Vector3(
                origin.x - player_center.x,
                origin.y - player_center.y,
                origin.z - player_center.z,
            )

            a = direction.x ** 2 + direction.z ** 2
            b = 2 * (oc.x * direction.x + oc.z * direction.z)
            c = oc.x ** 2 + oc.z ** 2 - player_radius ** 2

            discriminant = b ** 2 - 4 * a * c
            if discriminant < 0 or a < 1e-9:
                continue

            t = (-b - math.sqrt(discriminant)) / (2 * a)
            if t < 0:
                t = (-b + math.sqrt(discriminant)) / (2 * a)
            if t < 0 or t > closest_dist:
                continue

            hit_y = origin.y + direction.y * t
            if hit_y < player.position.y or hit_y > player.position.y + player_height:
                continue

            hit_pos = Vector3(
                origin.x + direction.x * t,
                hit_y,
                origin.z + direction.z * t,
            )

            if not self.game_map.has_line_of_sight(origin, hit_pos):
                continue

            closest_hit = ("player", pid, hit_pos, t)
            closest_dist = t

        for obs in self.game_map.obstacles:
            dist_to_obs = origin.distance_to(obs.position)
            if dist_to_obs > closest_dist + 50:
                continue

            min_x, min_z, max_x, max_z = obs.get_bounds()
            min_y = 0
            max_y = obs.height

            t_min_val = 0.0
            t_max_val = max_dist

            hit = True
            for axis_min, axis_max, orig, dir_comp in [
                (min_x, max_x, origin.x, direction.x),
                (min_y, max_y, origin.y, direction.y),
                (min_z, max_z, origin.z, direction.z),
            ]:
                if abs(dir_comp) < 1e-9:
                    if orig < axis_min or orig > axis_max:
                        hit = False
                        break
                else:
                    t1 = (axis_min - orig) / dir_comp
                    t2 = (axis_max - orig) / dir_comp
                    if t1 > t2:
                        t1, t2 = t2, t1
                    t_min_val = max(t_min_val, t1)
                    t_max_val = min(t_max_val, t2)
                    if t_min_val > t_max_val:
                        hit = False
                        break

            if hit and t_min_val < closest_dist and t_min_val > 0:
                hit_pos = Vector3(
                    origin.x + direction.x * t_min_val,
                    origin.y + direction.y * t_min_val,
                    origin.z + direction.z * t_min_val,
                )
                closest_hit = ("obstacle", obs.obstacle_id, hit_pos, t_min_val)
                closest_dist = t_min_val

        return closest_hit

    def _apply_damage(self, player: Player, damage: float) -> float:
        actual_damage = damage
        if player.armor > 0:
            armor_absorbed = min(player.armor, damage * 0.5)
            player.armor -= armor_absorbed
            actual_damage = damage - armor_absorbed

        player.health = max(0, player.health - actual_damage)
        player.last_hit_time = time.time()
        return actual_damage

    async def handle_reload(self, player_id: str):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        weapon = player.get_active_weapon()
        if not weapon or player.is_reloading:
            return

        if weapon.current_ammo >= weapon.magazine_size:
            return

        ammo_type_map = {
            "Pistol": "light_ammo",
            "SMG": "light_ammo",
            "Assault Rifle": "heavy_ammo",
            "LMG": "heavy_ammo",
            "Sniper Rifle": "heavy_ammo",
            "Shotgun": "shells",
        }
        ammo_type = ammo_type_map.get(weapon.name, "light_ammo")
        available_ammo = player.inventory.get(ammo_type, 0)

        if available_ammo <= 0:
            await self.send_to_player(player_id, {"type": "no_ammo"})
            return

        player.is_reloading = True
        player.reload_start_time = time.time()

        self.event_queue.append({
            "type": "reload_start",
            "player_id": player_id,
            "reload_time": weapon.reload_time,
        })

    async def handle_switch_weapon(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        index = data.get("weapon_index", 0)
        if 0 <= index < len(player.weapons):
            player.active_weapon_index = index
            player.is_reloading = False

    async def handle_pickup(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        item_id = data.get("item_id")
        item = self.game_map.loot_items.get(item_id)
        if not item or item.picked_up:
            return

        if player.position.distance_to(item.position) > 5.0:
            return

        item.picked_up = True

        if item.item_type == "weapon":
            if item.item_name in WEAPON_TEMPLATES:
                template = WEAPON_TEMPLATES[item.item_name]
                new_weapon = Weapon(
                    name=template.name,
                    damage=template.damage,
                    fire_rate=template.fire_rate,
                    magazine_size=template.magazine_size,
                    current_ammo=template.magazine_size,
                    reload_time=template.reload_time,
                    projectile_speed=template.projectile_speed,
                    weapon_range=template.weapon_range,
                )
                if len(player.weapons) < 3:
                    player.weapons.append(new_weapon)
                else:
                    dropped_weapon = player.weapons[player.active_weapon_index]
                    player.weapons[player.active_weapon_index] = new_weapon
                    drop_item = LootItem(
                        item_id=f"drop_{uuid.uuid4().hex[:8]}",
                        position=Vector3(player.position.x, 0, player.position.z),
                        item_type="weapon",
                        item_name=dropped_weapon.name.lower().replace(" ", "_"),
                    )
                    self.game_map.loot_items[drop_item.item_id] = drop_item
        elif item.item_type == "ammo":
            current = player.inventory.get(item.item_name, 0)
            player.inventory[item.item_name] = current + item.quantity
        elif item.item_type == "health":
            current = player.inventory.get(item.item_name, 0)
            player.inventory[item.item_name] = current + item.quantity
        elif item.item_type == "armor":
            if item.item_name == "light_armor":
                player.armor = min(player.armor + 50, 100)
            elif item.item_name == "heavy_armor":
                player.armor = min(player.armor + 100, 100)

        self.event_queue.append({
            "type": "item_picked_up",
            "player_id": player_id,
            "item_id": item_id,
        })

        await self.send_to_player(player_id, {
            "type": "inventory_update",
            "weapons": [w.to_dict() for w in player.weapons],
            "inventory": player.inventory,
            "armor": player.armor,
        })

    async def handle_drop(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        item_name = data.get("item_name")
        quantity = data.get("quantity", 1)

        if item_name in player.inventory and player.inventory[item_name] >= quantity:
            player.inventory[item_name] -= quantity
            if player.inventory[item_name] <= 0:
                del player.inventory[item_name]

            drop_item = LootItem(
                item_id=f"drop_{uuid.uuid4().hex[:8]}",
                position=Vector3(
                    player.position.x + random.uniform(-2, 2),
                    0,
                    player.position.z + random.uniform(-2, 2),
                ),
                item_type="ammo" if "ammo" in item_name else "health",
                item_name=item_name,
                quantity=quantity,
            )
            self.game_map.loot_items[drop_item.item_id] = drop_item

            self.event_queue.append({
                "type": "item_dropped",
                "item": drop_item.to_dict(),
            })

    async def handle_use_item(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player or player.state != PlayerState.ALIVE:
            return

        item_name = data.get("item_name")
        if item_name == "medkit" and player.inventory.get("medkit", 0) > 0:
            player.health = min(100, player.health + 75)
            player.inventory["medkit"] -= 1
            if player.inventory["medkit"] <= 0:
                del player.inventory["medkit"]
        elif item_name == "bandage" and player.inventory.get("bandage", 0) > 0:
            player.health = min(75, player.health + 15)
            player.inventory["bandage"] -= 1
            if player.inventory["bandage"] <= 0:
                del player.inventory["bandage"]

        await self.send_to_player(player_id, {
            "type": "inventory_update",
            "weapons": [w.to_dict() for w in player.weapons],
            "inventory": player.inventory,
            "health": player.health,
        })

    async def handle_disconnect(self, player_id: str):
        if player_id in self.players:
            self.players[player_id].connected = False
            self.players[player_id].state = PlayerState.DEAD
            self.event_queue.append({
                "type": "player_disconnected",
                "player_id": player_id,
                "username": self.players[player_id].username,
            })
        self.connected_websockets.pop(player_id, None)

    async def game_loop(self):
        logger.info("Game loop started")
        last_time = time.time()

        while True:
            current_time = time.time()
            dt = current_time - last_time
            last_time = current_time

            self.server_tick += 1

            self.update_game_state(dt, current_time)
            await self.broadcast_game_state(current_time)

            self.event_queue.clear()

            elapsed = time.time() - current_time
            sleep_time = max(0, self.tick_interval - elapsed)
            await asyncio.sleep(sleep_time)

    def update_game_state(self, dt: float, current_time: float):
        alive_players = [
            p for p in self.players.values()
            if p.state == PlayerState.ALIVE and p.connected
        ]
        connected_players = [p for p in self.players.values() if p.connected]

        if self.game_phase == GamePhase.WAITING:
            if len(connected_players) >= self.min_players_to_start:
                self.game_phase = GamePhase.DROPPING
                self.game_start_time = current_time
                self.zone.next_shrink_time = current_time + self.zone_phases[0]["delay"]
                logger.info("Game starting! Players dropping in...")
                self.event_queue.append({
                    "type": "game_phase_change",
                    "phase": self.game_phase.value,
                })

        elif self.game_phase == GamePhase.DROPPING:
            for player in alive_players:
                if player.position.y > 0:
                    player.position.y = max(0, player.position.y - 50 * dt)

            all_landed = all(p.position.y <= 0 for p in alive_players)
            if all_landed or current_time - self.game_start_time > 15:
                for p in alive_players:
                    p.position.y = 0
                self.game_phase = GamePhase.PLAYING
                logger.info("All players landed. Game is now PLAYING.")
                self.event_queue.append({
                    "type": "game_phase_change",
                    "phase": self.game_phase.value,
                })

        elif self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            self._update_zone(dt, current_time)
            self._update_zone_damage(dt, alive_players)
            self._update_reloads(current_time)

            if len(alive_players) <= 1 and len(connected_players) > 1:
                self.game_phase = GamePhase.ENDED
                winner = alive_players[0] if alive_players else None
                self.event_queue.append({
                    "type": "game_over",
                    "winner_id": winner.player_id if winner else None,
                    "winner_name": winner.username if winner else "Nobody",
                    "winner_kills": winner.kills if winner else 0,
                })
                logger.info(f"Game Over! Winner: {winner.username if winner else 'Nobody'}")

    def _update_zone(self, dt: float, current_time: float):
        if self.zone.is_shrinking:
            shrink_amount = self.zone.shrink_rate * dt
            self.zone.current_radius = max(
                self.zone.target_radius,
                self.zone.current_radius - shrink_amount,
            )

            if self.zone.current_radius <= self.zone.target_radius:
                self.zone.is_shrinking = False
                self.zone.phase += 1

                if self.zone.phase < len(self.zone_phases):
                    phase_data = self.zone_phases[self.zone.phase]
                    self.zone.next_shrink_time = current_time + phase_data["delay"]
                    self.zone.target_radius = phase_data["target_radius"]
                    self.zone.shrink_rate = phase_data["shrink_rate"]
                    self.zone.damage_per_second = phase_data["damage"]

                    offset_range = self.zone.current_radius * 0.3
                    self.zone.center.x += random.uniform(-offset_range, offset_range)
                    self.zone.center.z += random.uniform(-offset_range, offset_range)

                    half_w = self.game_map.width / 2
                    half_d = self.game_map.depth / 2
                    self.zone.center.x = max(-half_w + self.zone.target_radius,
                                              min(half_w - self.zone.target_radius, self.zone.center.x))
                    self.zone.center.z = max(-half_d + self.zone.target_radius,
                                              min(half_d - self.zone.target_radius, self.zone.center.z))

                    self.event_queue.append({
                        "type": "zone_update",
                        "zone": self.zone.to_dict(),
                    })
                else:
                    self.game_phase = GamePhase.FINAL_CIRCLE
        elif current_time >= self.zone.next_shrink_time and self.zone.phase < len(self.zone_phases):
            self.zone.is_shrinking = True
            phase_data = self.zone_phases[self.zone.phase]
            self.zone.target_radius = phase_data["target_radius"]
            self.zone.shrink_rate = phase_data["shrink_rate"]
            self.zone.damage_per_second = phase_data["damage"]

            self.event_queue.append({
                "type": "zone_shrinking",
                "zone": self.zone.to_dict(),
            })

    def _update_zone_damage(self, dt: float, alive_players: List[Player]):
        for player in alive_players:
            dist = player.position.distance_to(self.zone.center)
            if dist > self.zone.current_radius:
                damage = self.zone.damage_per_second * dt
                player.health = max(0, player.health - damage)
                if player.health <= 0:
                    player.state = PlayerState.DEAD
                    self.event_queue.append({
                        "type": "kill",
                        "killer_id": "zone",
                        "killer_name": "The Zone",
                        "victim_id": player.player_id,
                        "victim_name": player.username,
                        "weapon": "zone",
                        "headshot": False,
                        "timestamp": time.time(),
                    })

    def _update_reloads(self, current_time: float):
        for player in self.players.values():
            if player.is_reloading and player.state == PlayerState.ALIVE:
                weapon = player.get_active_weapon()
                if weapon and current_time - player.reload_start_time >= weapon.reload_time:
                    ammo_type_map = {
                        "Pistol": "light_ammo",
                        "SMG": "light_ammo",
                        "Assault Rifle": "heavy_ammo",
                        "LMG": "heavy_ammo",
                        "Sniper Rifle": "heavy_ammo",
                        "Shotgun": "shells",
                    }
                    ammo_type = ammo_type_map.get(weapon.name, "light_ammo")
                    available = player.inventory.get(ammo_type, 0)
                    needed = weapon.magazine_size - weapon.current_ammo
                    reload_amount = min(needed, available)

                    weapon.current_ammo += reload_amount
                    player.inventory[ammo_type] = available - reload_amount
                    if player.inventory[ammo_type] <= 0:
                        player.inventory.pop(ammo_type, None)

                    player.is_reloading = False

                    self.event_queue.append({
                        "type": "reload_complete",
                        "player_id": player.player_id,
                    })

    async def broadcast_game_state(self, current_time: float):
        if not self.connected_websockets:
            return

        all_players_data = {}
        for pid, player in self.players.items():
            if player.connected:
                all_players_data[pid] = player.to_dict(include_private=False)

        available_loot_nearby: Dict[str, List[dict]] = {}
        for pid, player in self.players.items():
            if not player.connected or player.state == PlayerState.DEAD:
                continue
            nearby_loot = []
            for item in self.game_map.loot_items.values():
                if not item.picked_up and player.position.distance_to(item.position) <= 100:
                    nearby_loot.append(item.to_dict())
            available_loot_nearby[pid] = nearby_loot

        base_state = {
            "type": "game_state",
            "tick": self.server_tick,
            "server_time": current_time,
            "game_phase": self.game_phase.value,
            "zone": self.zone.to_dict(),
            "players": all_players_data,
            "events": self.event_queue,
            "alive_count": len([
                p for p in self.players.values()
                if p.state == PlayerState.ALIVE and p.connected
            ]),
            "kill_feed": self.kill_feed[-10:],
        }

        tasks = []
        for pid, ws in list(self.connected_websockets.items()):
            player = self.players.get(pid)
            if not player:
                continue

            player_state = dict(base_state)
            player_state["your_data"] = player.to_dict(include_private=True)
            player_state["nearby_loot"] = available_loot_nearby.get(pid, [])

            # Provide line-of-sight hints for client-side filtering optimization
            # The client receives ALL player positions but we provide LOS data
            # so the client can make rendering decisions
            los_data = {}
            if player.state == PlayerState.ALIVE:
                eye_pos = Vector3(
                    player.position.x,
                    player.position.y + (1.6 if not player.is_crouching else 1.0),
                    player.position.z,
                )
                for other_pid, other_player in self.players.items():
                    if other_pid == pid or not other_player.connected:
                        continue
                    if other_player.state == PlayerState.DEAD:
                        los_data[other_pid] = {
                            "visible": False,
                            "distance": 0,
                            "in_range": False,
                        }
                        continue

                    other_eye = Vector3(
                        other_player.position.x,
                        other_player.position.y + 0.9,
                        other_player.position.z,
                    )
                    distance = eye_pos.distance_to(other_eye)
                    in_render_range = distance <= 500
                    has_los = False
                    if in_render_range:
                        has_los = self.game_map.has_line_of_sight(eye_pos, other_eye)

                    los_data[other_pid] = {
                        "visible": has_los,
                        "distance": round(distance, 1),
                        "in_range": in_render_range,
                    }

            player_state["los_hints"] = los_data

            tasks.append(self._send_state(pid, ws, player_state))

        if tasks:
            await asyncio.gather(*tasks, return_exceptions=True)

    async def _send_state(self, player_id: str, ws, state: dict):
        try:
            await ws.send(json.dumps(state))
        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection lost for {player_id} during broadcast")
            await self.handle_disconnect(player_id)
        except Exception as e:
            logger.error(f"Error sending state to {player_id}: {e}")

    async def send_to_player(self, player_id: str, data: dict):
        ws = self.connected_websockets.get(player_id)
        if ws:
            try:
                await ws.send(json.dumps(data))
            except websockets.exceptions.ConnectionClosed:
                await self.handle_disconnect(player_id)
            except Exception as e:
                logger.error(f"Error sending to {player_id}: {e}")

    def get_server_stats(self) -> dict:
        alive = len([p for p in self.players.values()
                      if p.state == PlayerState.ALIVE and p.connected])
        connected = len([p for p in self.players.values() if p.connected])
        return {
            "tick": self.server_tick,
            "connected_players": connected,
            "alive_players": alive,
            "game_phase": self.game_phase.value,
            "zone_radius": self.zone.current_radius,
            "zone_phase": self.zone.phase,
            "total_loot_items": len(self.game_map.loot_items),
            "available_loot": len([i for i in self.game_map.loot_items.values() if not i.picked_up]),
        }


class AdminConsole:
    """Simple admin interface for server management."""

    def __init__(self, server: BattleRoyaleServer):
        self.server = server

    async def run(self):
        while True:
            await asyncio.sleep(10)
            stats = self.server.get_server_stats()
            logger.info(
                f"[Stats] Tick: {stats['tick']} | "
                f"Players: {stats['connected_players']} connected, "
                f"{stats['alive_players']} alive | "
                f"Phase: {stats['game_phase']} | "
                f"Zone: R={stats['zone_radius']:.0f} P={stats['zone_phase']}"
            )


async def main():
    server = BattleRoyaleServer(
        host="0.0.0.0",
        port=8765,
        tick_rate=20,
        max_players=100,
        min_players_to_start=2,
    )

    admin = AdminConsole(server)
    admin_task = asyncio.create_task(admin.run())

    await server.start()


if __name__ == "__main__":
    asyncio.run(main())